/// <summary>
///    The <c>SalesConfirmController</c> class is the helper class for the associated  report.
/// </summary>
public class ETG_AgreementConfirmController extends SrsReportRunController
{   
    ETG_AgreementConfirmationRDPContract                contract;
    ModuleSalesPurch                                    moduleType;
    PurchAgreementHeaderHistory                         purchAgreementHeaderHistory;
    SalesAgreementHeaderHistory                         salesAgreementHeaderHistory;

}

Method.Source:
 protected void preRunModifyContract()
{
    str                     reportnameLocal;
    contract = this.parmReportContract().parmRdpContract();
    this.getReportContract().parmReportCaption("@SYS316853");

    switch (args.record().TableId)
    {
        case  tableNum(SalesAgreementHeaderHistory):
            moduleType = ModuleSalesPurch::Sales;
            contract.parmModuleSalesPurch(moduleType);
            salesAgreementHeaderHistory =  args.record();                
            contract.parmSalesAgreementId(salesAgreementHeaderHistory.SalesNumberSequence);
            contract.parmSalesHeaderHistory(salesAgreementHeaderHistory.RecId);
            reportnameLocal = ssrsReportStr(ETG_AgreementConfirmationRpt, Sales);
            break;
        case  tableNum(PurchAgreementHeaderHistory):
            moduleType = ModuleSalesPurch::Purch; 
            contract.parmModuleSalesPurch(moduleType);
            purchAgreementHeaderHistory = args.record();
            contract.parmPurchAgreementId(purchAgreementHeaderHistory.PurchNumberSequence);
            contract.parmPurchHeaderHistory(purchAgreementHeaderHistory.RecId);
            if(curExt() == "O051")
            {
                reportnameLocal = ssrsReportStr(ETG_AgreementConfirmationRpt, Purch_O051);
            }
            else
            {
                reportnameLocal = ssrsReportStr(ETG_AgreementConfirmationRpt, Purch);
            }
            break;
        default:
            throw error(Error::wrongUseOfFunction(funcName()));
    }
    this.parmReportName(reportnameLocal);
    this.parmReportContract().parmReportName(this.parmReportName());
}

/// </summary>
/// <param name="_args">
/// The <c>Args</c> object.
/// </param>
public static void main(Args _args)
{
    AgreementHeaderHistory                              agreementHeaderHistory;
    recId                                               recId;
    ModuleSalesPurch                                    moduleType;
    ETG_AgreementConfirmController agreementConfirmController = new ETG_AgreementConfirmController();

    if (_args.record())
    {
        agreementConfirmController.parmArgs(_args);
        if(curExt() == "O051")
        {
            agreementConfirmController.parmReportName(ssrsReportStr(ETG_AgreementConfirmationRpt, Purch_O051));
        }
        else
        {
            agreementConfirmController.parmReportName(ssrsReportStr(ETG_AgreementConfirmationRpt, Purch));
        }
        agreementConfirmController.parmShowDialog(false);
        agreementConfirmController.startOperation();
    }
}
